"""
MKT Original Commentary — Isaiah chapters 37–40
Run: python3 scripts/zc-original-isaiah-37-40.py

Chs 37-39 are the "historical appendix" (parallel to 2 Kings 18-20); ch 40 opens
the great "Second Isaiah" prologue (chs 40-55) with the Comfort oracle.

Key translation decisions:
- 37:16 kĕrûḇîm: "cherubim" — retained as a technical term; YHWH is "enthroned above
  the cherubim," a temple-throne formula.
- 38:12 dôr: can mean "generation" or "dwelling/circle"; here the tent/generation
  double meaning is both available and appropriate for Hezekiah's mortality meditation.
- 38:18-19: the praise-argument for healing is often misread as a contractual claim;
  it is better read as Hezekiah's theological protest — Sheol silences worship.
- 40:3 qōl qōrēʾ: "a voice calling" (already entered); all four gospels cite this as
  the prophetic mandate of John the Baptist.
- 40:6-8 ḥāṣîr / dĕbar ʾĕlōhênû: "grass" / "the word of our God endures forever" —
  1 Pet 1:23-25 quotes vv.6-8 as the word by which believers are born again.
- 40:13 mî-tikkēn ʾet-rûaḥ Yhwh: cited in Rom 11:34 and 1 Cor 2:16.
- 40:31 qōwê Yhwh yaḥălîpû kōaḥ: "those who wait on YHWH will exchange/renew strength."
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
  "37": {
    "1": '<p><strong>wayyiqrāʿ ʾet-bigdāyw</strong> — "he tore his garments" — the standard mourning rite. <strong>wayyitkas bassāq</strong> — "covered himself with sackcloth" (<em>śaq</em>, H8242, coarse cloth worn in grief and penitence). <strong>wayyābōʾ bêt Yhwh</strong> — "went into the house of YHWH" — Hezekiah\'s response to the Assyrian threat is first liturgical: to the temple, not the war council. The pairing of mourning ritual and temple approach models the appropriate response to existential crisis in the Isaianic framework.</p>',
    "2": '<p>Hezekiah sends <em>ʾelyāqîm</em> (household administrator), <em>šebnâ</em> (secretary), and the senior priests (<em>ziqnê hakkohanîm</em>) — a delegation of his court\'s highest officials — to Isaiah. The phrase <strong>mekussîm bassāq</strong> — "clothed in sackcloth" — indicates the officials also come in mourning dress. The symbolism of sending the sackcloth-wearing court to the prophet signals dependence on YHWH\'s word rather than military counsel.</p>',
    "3": '<p><strong>yôm ṣārâ wĕtôkēḥâ ûnĕʾāṣâ</strong> — "a day of distress, rebuke, and disgrace" — three nouns stacking the severity of the moment. The crucial idiom: <strong>bāʾû bānîm ʿad-mašbēr wĕkōaḥ ʾayin lĕlēdâ</strong> — "children have come to the point of birth but there is no strength to deliver" — a medical metaphor for crisis at the point of maximum tension with no capacity to resolve it. The labor-without-delivery image is a Hebrew idiom for futile anguish.</p>',
    "4": '<p><strong>yišmaʿ Yhwh ʾĕlōheykā</strong> — "perhaps YHWH your God will hear" — the tentative hope expressed through the envoys. The key phrase: <strong>bĕʿad šĕʾērit hannimṣāʾâ</strong> — "on behalf of the remnant that is still found" — the <em>šĕʾērît</em> (remnant) motif that is central to Isaiah\'s theology from ch. 7 onward. Hezekiah\'s appeal is not for himself but for the surviving remnant — the theological category that anchors YHWH\'s covenant faithfulness.</p>',
    "5": '<p>Isaiah\'s initial response comes quickly — the servants arrive, and he immediately gives a word (<em>wayyōmer ʾălêhem Yĕšaʿyāhû</em>). This contrasts with other prophets who require time or ritual preparation. The quickness of Isaiah\'s response reflects his continuous engagement with YHWH\'s word — he is already prepared to speak.</p>',
    "6": '<p><strong>ʾal-tîrāʾ</strong> — "do not be afraid" — the standard oracle of salvation formula (cf. 35:4; 41:10; 43:1). <strong>middĕbrê hannaʿărîm</strong> — "from the words of the young men/servants" — YHWH characterizes the Assyrian blasphemy as coming from insignificant underlings. The divine perspective reframes the crisis: what appeared as an overwhelming imperial army is dismissed as the bragging of <em>naʿărîm</em> (young men, attendants).</p>',
    "7": '<p><strong>hinnî nōtēn bô rûaḥ</strong> — "behold, I am putting a spirit in him" — the divine intervention will be internal to Sennacherib, not external military defeat alone. The spirit (<em>rûaḥ</em>) that YHWH puts in him will cause him to hear a rumor (<em>šĕmûʿâ</em>) and return to his land, where he will fall by the sword. The prophetic word is unconditional and specific — both the how (rumor) and the where (his own land) are named.</p>',
    "8": '<p>Sennacherib\'s field commander returns to find the king fighting against Libnah (<em>Libnâ</em>) — a Shephelah city — having already withdrawn from Lachish. The military narrative confirms the geopolitical instability that will make the king vulnerable to rumors and distraction. Isaiah\'s prophetic word (v.7) is already beginning to unfold through natural events.</p>',
    "9": '<p><strong>wayyišmaʿ ʿal-Tîrhāqâ melek-Kûš</strong> — "he heard concerning Tirhakah king of Cush" — the Ethiopian pharaoh of the 25th Dynasty who was advancing against Sennacherib. This is the "rumor" of v.7. The military intelligence about Tirhakah forces Sennacherib to send a letter to Hezekiah rather than attacking personally — the shift from army to letter marks a psychological retreat disguised as threat.</p>',
    "10": '<p>The letter\'s argument: <strong>ʾal-yaššîʾakā ʾĕlōheykā</strong> — "do not let your God deceive you" — a theological attack on Hezekiah\'s trust in YHWH. The claim is that Sennacherib\'s pattern of victories proves the futility of any divine protection. The gods of the nations have consistently failed; YHWH will be no different. This is the blasphemy that triggers Hezekiah\'s temple prayer.</p>',
    "11": '<p>The catalogue of Assyrian conquests: the Assyrian king addresses Hezekiah with direct reference to what Assyrian kings (<em>malkê ʾaššûr</em>) did to all lands — <em>hōḥărimûm</em>, "devoted to destruction/utterly destroyed" (<em>ḥāram</em>, H2763, the verb of total destruction/holy war). The claim is that herem (total destruction) has been applied universally and YHWH\'s Jerusalem will be no exception.</p>',
    "12": '<p>The defeated nations named: Gozan (<em>Gôzān</em>), Haran (<em>Ḥārān</em>), Rezeph (<em>Reṣep</em>), and the people of Eden in Telassar (<em>Ṭelʾaśśar</em>) — all Aramean/Mesopotamian kingdoms already absorbed by Assyria. The list is designed to overwhelm with precedent. The rhetorical question <em>mî hên ʾăšer hiṣṣîlûm</em> ("where are the gods who delivered them?") challenges Hezekiah to produce a single counter-example.</p>',
    "13": '<p>The catalogue continues with Hamath, Arpad, Sepharvaim, Hena, and Ivvah — all cities and regions conquered. The roll-call of defeated gods and nations functions as a liturgy of despair designed to produce surrender. What makes Hezekiah\'s prayer (vv.15-20) so powerful is that it directly engages this theology of comparative divine power.</p>',
    "14": '<p><strong>wayyiqqaḥ Ḥizqiyyāhû ʾet-hassĕpārîm</strong> — "Hezekiah took the letters" (<em>sĕpārîm</em>, plural — perhaps multiple documents or a letter and accompanying threats). <strong>wayyipprōśēm lipnê Yhwh</strong> — "spread them out before YHWH." The physical act of spreading the letter in the temple is unprecedented — Hezekiah literally brings the human document into the divine court, making YHWH the judge of Sennacherib\'s claims. This is prayer as legal action.</p>',
    "15": '<p>The prayer begins with the address formula: <strong>Yhwh ṣĕbāʾôt ʾĕlōhê yiśrāʾēl yōšēb hakĕrûḇîm</strong> — "YHWH of hosts, God of Israel, enthroned above the cherubim" — the full cultic title. <strong>ʾattâ hûʾ hāʾĕlōhîm lĕḇaddĕkā lĕkol mamlĕkôt hāʾāreṣ</strong> — "you alone are God over all kingdoms of the earth." The prayer begins with the claim Sennacherib denied — YHWH\'s universal sovereignty — stated as direct address to YHWH himself.</p>',
    "16": '<p><strong>yōšēb hakĕrûḇîm</strong> — "enthroned above the cherubim" — the technical formula for YHWH\'s presence above the ark (1 Sam 4:4; 2 Sam 6:2; Ps 80:1). The <em>kĕrûḇîm</em> are the heavenly attendants whose wings form YHWH\'s throne; they are not the storm/war-deity cherubim of Babylonian iconography but the covenant guardians of YHWH\'s holiness. Hezekiah appeals to YHWH as the transcendent creator who made heaven and earth (<em>ʿāśîtā ʾet-haššāmayim wĕʾet-hāʾāreṣ</em>).</p>',
    "17": '<p><strong>haṭṭēh Yhwh ʾoznĕkā ûšmaʿ</strong> — "incline your ear and hear" — the petitionary formula characteristic of royal psalms (Ps 17:6; 31:2; 86:1). <strong>pĕqaḥ Yhwh ʿêneykā ûrʾēh</strong> — "open your eyes and see" — the request for divine attention activates the anthropomorphic divine perception imagery. <strong>dibĕrê Sannĕḥērîḇ ʾăšer šālaḥ lĕḥārēp ʾĕlōhîm ḥāy</strong> — "the words of Sennacherib who sent to taunt the living God" — <em>ḥāy</em> (living) is the decisive contrast with the dead idols of the nations.</p>',
    "18": '<p><strong>ʾākēn Yhwh</strong> — "it is true, YHWH" — Hezekiah acknowledges the historical facts Sennacherib cited. <strong>hḥărîbû malkê ʾaššûr</strong> — "the Assyrian kings have laid waste all the lands" — the prayer is not naive. Hezekiah admits the military reality before making the theological argument. This intellectual honesty in prayer is itself a form of faith — praying with eyes open to the real situation.</p>',
    "19": '<p><strong>wĕnātĕnû ʾet-ʾĕlōhêhem bāʾēš</strong> — "they threw their gods into the fire and destroyed them" — Hezekiah now makes the theological argument: those gods were <em>not gods</em> (<em>kî lōʾ ʾĕlōhîm hēmmâ</em>) but the work of human hands (<em>maʿăśēh yĕdê ʾādām</em>), wood and stone (<em>ʿēṣ wāʾeben</em>). They could be burned because they were merely material objects. This is the Isaianic idol-polemic at its sharpest (cf. 44:9-20).</p>',
    "20": '<p><strong>wĕʿattâ Yhwh ʾĕlōhênû hôšîʿēnû miyyādô</strong> — "and now, O YHWH our God, save us from his hand" — the petition itself is brief after the long theological setup. The purpose clause is striking: <strong>lĕmaʿan yĕdĕʿû kol-mamlĕkôt hāʾāreṣ kî ʾattâ Yhwh lĕḇaddekā</strong> — "so that all kingdoms of the earth may know that you alone are YHWH." Salvation is requested not merely for Israel\'s sake but for YHWH\'s universal glory — a missionary motivation embedded in a prayer of crisis.</p>',
    "21": '<p>Isaiah sends Hezekiah a word — <strong>šālaḥ Yĕšaʿyāhû ben-ʾĀmôṣ</strong> — confirming that his prayer was heard (<em>yaʿan ʾăšer hitpallaltā</em>, "because you prayed"). The word of YHWH is addressed specifically against (<em>ʿālāyw</em>) Sennacherib. The prayer\'s success is explicitly linked to its content — Hezekiah prayed, therefore YHWH speaks. The connection between prayer and divine speech is direct and immediate.</p>',
    "22": '<p><strong>bĕtûlat bat-ṣiyyôn</strong> — "the virgin daughter of Zion" — the personification of Jerusalem as a young woman. <strong>lāzâ lēz bāz lēz ʾaḥărêkā nūdâ rōʾšāh bat-yĕrûšālaim</strong> — "she despises you, she scorns you; behind your back she wags her head, O daughter of Jerusalem." The image of the humiliated Assyrian king being mocked by the city he could not conquer is one of Isaiah\'s most vivid rhetorical reversals — the greatest military power taunted by a city-girl.</p>',
    "23": '<p><strong>ʾet-mî ḥēraptā ûgiddaptā</strong> — "whom have you taunted and reviled?" — the rhetorical question reveals the ultimate target of Sennacherib\'s words. He has not merely insulted Judah but the Holy One of Israel (<em>ʾet-qĕdôš yiśrāʾēl</em>). The elevation of the conflict from Judah-versus-Assyria to YHWH-versus-Assyria reframes the entire narrative.</p>',
    "24": '<p>Sennacherib\'s arrogance described: cutting down Lebanon\'s cedars and choice firs (<em>kōrĕtî qômat ʾărāzāyw mibḥar bĕrōšāyw</em>), entering the innermost height (<em>mārôm qiṣṣô</em>), the forest of his Carmel. The cedar-cutting is both military metaphor (cutting down armies) and ecological reality (the Assyrian army consumed massive timber). The self-exaltation of the empire is mirrored in its consumption of creation.</p>',
    "25": '<p><strong>ʾănî qartî wĕšātîtî mêm zarîm</strong> — "I dug and drank water from strange wells" — the Assyrian king\'s claim to have conquered waterless wilderness and survived by force of imperial will. <strong>wĕʾaḥărîb bĕkap pĕʿāmay kol yĕʾōrê māṣôr</strong> — "I will dry up with the soles of my feet all the rivers of Egypt" — the boast reaches cosmic proportions. The drying of rivers was YHWH\'s act at the Exodus; Sennacherib usurps this divine prerogative.</p>',
    "26": '<p><strong>hălōʾ šāmaʿtā</strong> — "Have you not heard?" — YHWH speaks, now directly addressing Sennacherib. <strong>lĕmērāḥôq ʾōtāh ʿāśîtî</strong> — "from long ago I made it (the plan)." Everything Assyria has done — the conquests, the devastation — was YHWH\'s instrument (<em>ʿēṣōt qedem</em>, "plans of old"). The empire did not act autonomously; it fulfilled YHWH\'s predetermined purpose. The <em>ʿēṣâ</em> of YHWH (14:26-27; 25:1) governs even its enemies.</p>',
    "27": '<p><strong>wĕyōšĕbêhem qĕṣar-yāḏ</strong> — "their inhabitants were short of hand" — an idiom for powerlessness/helplessness. The defeated cities were like <em>ʿēśeḇ śādeh ûyereq deshe</em> (grass of the field and green vegetation) — weak plants, not through Assyria\'s strength but through YHWH\'s preordained limitation of them. The demolished cities were <em>before</em> dismayed — their devastation was already determined.</p>',
    "28": '<p><strong>šibteḵā wĕṣēʾtĕkā ûḇōʾăkā yāḏaʿtî</strong> — "your sitting and going out and coming in I know" — YHWH\'s comprehensive surveillance of Sennacherib. The three pairs (sitting/rising, going out/coming in) together represent the totality of human activity — YHWH monitors all of it. <strong>wĕʾēt hithraggĕzĕkā ʾēlay</strong> — "and your raging against me" — the surveillance is specifically interested in the rage directed at YHWH.</p>',
    "29": '<p><strong>yaʿan hithraggĕzĕkā ʾēlay wĕšaʾănānĕkā ʿālâ bĕʾoznāy</strong> — "because your raging against me and your arrogance have come to my ears." The consequence: <strong>wĕśamtî ḥaqqî bĕʾapkā ûmaśĕgarî bĕśĕpātêkā</strong> — "I will put my hook in your nose and my bit in your lips." The animal-capture imagery (<em>ḥāq</em>, hook through nose; <em>maśgēr</em>, bit in lips — used to control horses and led animals) reduces the conqueror of nations to a led beast. YHWH will return him by the way he came.</p>',
    "30": '<p>The sign for Hezekiah: <strong>ʾākôl haššānâ hazzōʾt sĕpîaḥ ûbaššānâ haššĕnît śāḥîš</strong> — "eat this year what grows by itself, and in the second year what springs from that; but in the third year sow and reap, plant vineyards and eat their fruit." The three-year agricultural restoration sign confirms that YHWH\'s word to Hezekiah will be verified by the land\'s recovery — the sign is specifically agricultural, addressing the normal cycle of planting and harvest disrupted by siege.</p>',
    "31": '<p><strong>wĕyāspâ pĕlêṭat bêt-yĕhûdâ hannišʾārt šōreš lĕmattâ wĕʿāśâ pĕrî lĕmaʿlâ</strong> — "the surviving remnant of the house of Judah will again take root downward and bear fruit upward" — the classic remnant-restoration metaphor combining botanical imagery (root/fruit) with the vertical movement of spiritual vitality. This is the Isaiah 6:13 "holy seed" in its positive form — the remnant as the seedbed of restoration.</p>',
    "32": '<p><strong>kî miYĕrûšālaim tēṣēʾ šĕʾērît ûpĕlêṭâ mēhar ṣiyyôn</strong> — "for out of Jerusalem a remnant will go forth, and out of Mount Zion a band of survivors" — the city is the source from which the remnant disperses and from which covenant life is renewed. <strong>qinʾat Yhwh ṣĕbāʾôt taʿăśeh zōʾt</strong> — "the zeal of YHWH of hosts will accomplish this" — the same formula as 9:7 (the Davidic ruler\'s kingdom) — divine zeal (<em>qinʾâ</em>) is the engine of both promises.</p>',
    "33": '<p>The unconditional protection oracle for Jerusalem: <strong>lōʾ yāḇōʾ ʾel-hāʿîr hazzōʾt</strong> — "he will not enter this city." The Assyrian will not shoot an arrow (<em>lōʾ-yidreh šām ḥēṣ</em>), come before it with a shield (<em>lōʾ-yĕqaddĕmennāh māgēn</em>), or cast up a siege ramp (<em>lōʾ-yišpōk ʿāleyhā sōlĕlâ</em>). The three negated military actions specify the complete defeat of the Assyrian siege strategy.</p>',
    "34": '<p><strong>baddereḵ ʾăšer yāḇōʾ bāh yāšûḇ</strong> — "by the way that he came, by that he will return" — the return formula that matches v.29\'s hook-and-bit imagery. The direction reversal — advance replaced by retreat on the same road — is the sign of YHWH\'s control over the campaign\'s trajectory. YHWH declares this in advance (<em>nĕʾum-Yhwh</em>, oracle of YHWH) to prove that the event is his action, not chance.</p>',
    "35": '<p><strong>ûgannôtî ʿal-hāʿîr hazzōʾt lĕhôšîʿāh</strong> — "I will defend this city to save it" — the double motivation: <strong>lĕmaʿanî ûlĕmaʿan dāwid ʿabdî</strong> — "for my own sake and for the sake of David my servant." The salvation is not based on Hezekiah\'s righteousness alone but on YHWH\'s self-commitment (divine honor) and his Davidic covenant (<em>bĕrît dāwid</em>). The two grounds are inseparable: YHWH\'s name and David\'s covenant.</p>',
    "36": '<p><strong>wayyēṣēʾ malaʾk Yhwh wayyak bĕmaḥănēh ʾaššûr</strong> — "the angel of YHWH went out and struck down 185,000 in the Assyrian camp." The single agent, the single night, the massive number — the miracle is narrated with stark economy. <strong>wayyaškîmû babbōqer wĕhinnēh kullām pĕgarîm mētîm</strong> — "in the morning, they arose and behold, all of them were dead corpses." The contrast between the sleeping soldiers\' expectation of victory and the morning discovery of mass death is the narrative climax of the Assyrian crisis.</p>',
    "37": '<p>Sennacherib departs — <strong>wayyisaʿ wayyēlek wayyāšāb Sannĕḥērîḇ</strong> — "he set out, departed, and returned" — and dwelt in Nineveh. The fulfilment of Isaiah\'s prophecy (v.7: "he will return to his land") is stated without elaboration. The brevity is rhetorical: the great conqueror\'s retreat is dismissed in three verbs.</p>',
    "38": '<p><strong>wayhî hûʾ mištaḥăweh bêt nisrōk ʾĕlōhāyw</strong> — "he was worshiping in the house of Nisroch his god" — the final irony: the king who mocked YHWH is killed while worshiping his own god, in his own temple, by his own sons. <strong>wĕʾadrammeleḵ wĕśarʾeṣer bānāyw hikkuhû ḇaḥereb</strong> — "his sons Adrammelech and Sharezer struck him with the sword." The prophecy (v.7) is completely fulfilled. YHWH\'s word through Isaiah produced Sennacherib\'s defeat, retreat, and assassination.</p>',
  },
  "38": {
    "1": '<p><strong>ṣaw lĕbêtekā</strong> — "put your house in order/command your household" (<em>ṣāwâ</em>, to command; literally "command to your house"). This is the standard phrase for dying preparations — making arrangements for succession, inheritance, and burial. <strong>kî mēt ʾattâ wĕlōʾ tiḥyeh</strong> — "for you shall die and not live" — the death sentence is absolute and conditional-free. YHWH speaks it through the prophet without softening.</p>',
    "2": '<p><strong>wayyāsseb Ḥizqiyyāhû ʾet-pānāyw ʾel-haqqîr</strong> — "Hezekiah turned his face to the wall" — the physical posture of private, intense prayer. The turn away from the sickroom audience toward the wall is both practical (privacy) and symbolic (orientation toward YHWH, away from human society). <strong>wayyitpallel ʾel-Yhwh</strong> — "and prayed to YHWH" — the prayer follows immediately.</p>',
    "3": '<p><strong>hithallaktî lĕpāneykā beʾĕmet</strong> — "I have walked before you in truth/faithfulness" (<em>ʾemet</em>, H571, truth, reliability, fidelity — one of the covenant character terms). <strong>ûbĕlēḇ šālēm</strong> — "with a wholehearted/complete heart" (<em>šālēm</em>, complete, undivided). <strong>wĕhaṭṭôb bĕʿêneykā ʿāśîtî</strong> — "I have done what is good in your eyes." Hezekiah\'s prayer appeals to covenant fidelity, not merely divine mercy — he presents his life as evidence of faithfulness. <strong>wayyibkĕ Ḥizqiyyāhû bĕkî gādôl</strong> — "Hezekiah wept with great weeping."</p>',
    "4": '<p>The divine response comes <strong>wayhî dĕbar-Yhwh ʾel-Yĕšaʿyāhû</strong> — "the word of YHWH came to Isaiah" — before the prophet has even left the middle court (<em>ḥāṣēr hattîkônâ</em>). The speed of divine response is emphasized: the prayer was heard immediately. Isaiah had delivered a death sentence (v.1) and now receives a reversal from YHWH — both words are YHWH\'s word, showing that divine pronouncements can be conditional on human response.</p>',
    "5": '<p><strong>šûb wĕʾāmartā ʾel-Ḥizqiyyāhû</strong> — "return and say to Hezekiah" — Isaiah is sent back. <strong>šāmaʿtî ʾet-tĕpillatekā rāʾîtî ʾet-dimʿāteykā</strong> — "I have heard your prayer, I have seen your tears" — the two verbs address the two modes of Hezekiah\'s petition: spoken prayer and wept tears. Both were received. <strong>hinnî yōsip ʿal-yāmeykā ḥāmēš ʿeśrēh šānâ</strong> — "I will add fifteen years to your days." The specific number makes the promise verifiable.</p>',
    "6": '<p><strong>ûmikkaP melek ʾaššûr ʾaṣṣîlĕkā wĕʾet-hāʿîr hazzōʾt</strong> — "and I will deliver you and this city from the hand of the king of Assyria" — the healing is coupled with the deliverance of Jerusalem, connecting Hezekiah\'s personal crisis to the national crisis of ch. 37. The two promises are simultaneous: king healed + city defended. <strong>wĕgannōtî ʿal-hāʿîr hazzōʾt</strong> — "I will defend this city" — repeating 37:35.</p>',
    "7": '<p>The sign: <strong>wĕzeh-lĕkā hāʾôt mēʾēt Yhwh</strong> — "and this is the sign for you from YHWH." The sign authenticates the promise before it is fulfilled — it is evidence designed to produce faith, not just information. The reversal of the sun\'s shadow on the sundial of Ahaz (<em>maʿălôt ʾāḥāz</em>) — moving backward rather than forward — is an extraordinary astronomical sign. The shadow going backward (<em>šāḇâ hāṣēl ʿeśer maʿălôt</em>) is a temporal reversal that corresponds to the temporal gift of fifteen added years.</p>',
    "8": '<p><strong>hinnî mēšîḇ ʾet-ṣel hammaʿălôt</strong> — "behold, I will make the shadow retreat on the steps" — the causative of <em>šûḇ</em> (return). The sign is explicitly YHWH\'s action (<em>ʾănî</em>, first person), not a natural phenomenon misinterpreted. The sun returning ten steps on the sundial of Ahaz (<em>maʿălôt ʾāḥāz</em>) is a specific, localized event that authenticates a specific, localized promise. The sign does not announce cosmic reversal but personal restoration.</p>',
    "9": '<p><strong>miktāb lĕḥizqiyyāhû melek-yĕhûdâ bĕḥalōtô wayyeḥî mēḥolyô</strong> — "the writing of Hezekiah king of Judah when he was ill and recovered from his illness" — the superscription of the Song of Hezekiah (vv.10-20). <em>miktāb</em> (H4385) can mean a written text, inscription, or poem — a form used for composed literary pieces (cf. Ps 16:1; 56:1 <em>miktam</em>). The psalm is a thanksgiving composed in retrospect from the perspective of survival.</p>',
    "10": '<p><strong>ʾănî ʾāmartî bidmî yāmay</strong> — "I said in the noontide/prime of my days" — <em>dĕmî</em> (H1824) suggests the still point, the midpoint — cut off in the middle of his years. <strong>ʾēlĕkâ bĕšaʿărê šĕʾôl</strong> — "I will go to the gates of Sheol" — the image of Sheol as a city with gates (cf. Ps 107:18; Job 38:17; Matt 16:18). <strong>puqqadtî yeter šĕnōtāy</strong> — "I am deprived of the rest of my years" (<em>pāqad</em>, here in the pual — to be visited in deprivation, counted off, assigned to loss).</p>',
    "11": '<p><strong>ʾāmartî lōʾ-ʾerʾeh Yāh Yāh bĕʾereṣ haḥayyîm</strong> — "I said I will not see Yah, Yah, in the land of the living" — the doubled <em>Yāh</em> (the short form of YHWH) intensifies the loss: not just life but the vision of YHWH in the assembly is what Hezekiah mourns. <strong>lōʾ-ʾabbîṭ ʾādām ʿôd ʿim-yôšĕbê ḥāḏel</strong> — "I shall look no more upon man among the inhabitants of the world" (<em>ḥāḏel</em>, H2309, the cessation/world of the deceased — an unusual term for the underworld).</p>',
    "12": '<p><strong>dôrî nissaʿ wĕniglâ minnî kĕʾōhel rōʿî</strong> — "my dwelling/generation is pulled up and removed from me like a shepherd\'s tent" (<em>dôr</em>, H1755, here in its rare meaning of "circle/dwelling/generation"). The tent imagery: a nomad\'s temporary shelter that can be struck and moved — death is the collapse and removal of one\'s dwelling. <strong>qippadtî kāʾōrēg ḥayyay</strong> — "like a weaver I roll up my life" (<em>qāpad</em>, to roll up or draw together — the life as a finished web being rolled up from the loom).</p>',
    "13": '<p><strong>šiwitî ʿad-bōqer</strong> — "I waited until morning" — the long night of illness. <strong>kaʾărî kēn yĕšabbēr kol-ʿaṣmōtāy</strong> — "like a lion he breaks all my bones" — the illness personified as a lion crushing bones. The identification of YHWH as the source of the illness (the implied subject of "he breaks") reflects the ancient Hebrew theology that sickness was within YHWH\'s sovereign permission, not outside it — which is precisely why prayer to YHWH can heal.</p>',
    "14": '<p><strong>kĕsûs ʿāgûr kēn ʾăṣappṣēp</strong> — "like a swallow or crane (<em>sûs ʿāgûr</em>) I chirp" — the plaintive bird-cry as a metaphor for weak, inarticulate prayer. The species identification of <em>sûs</em> and <em>ʿāgûr</em> is debated: possibly "swallow and crane" or "swift and turtledove." <strong>ʾehgeh kĕyônâ</strong> — "I moan like a dove." Three bird-sounds (chirping, twittering, moaning) describe the wordless quality of extreme illness prayer. <strong>dallû ʿênay lammārôm</strong> — "my eyes are weary looking upward" — exhausted, persistent upward orientation.</p>',
    "15": '<p><strong>mā-ʾaddabbēr wĕʾāmar lî</strong> — "what shall I say, since he has both spoken and acted?" — Hezekiah is silenced by the reality of what YHWH has done. <strong>ʾeddaddeh kol-šĕnôtay ʿal-mar napšî</strong> — "I must walk carefully all my years because of the bitterness of my soul" — the surviving years are now lived under the shadow of the near-death, with a chastened and careful step (<em>dādâ</em>, to walk slowly/carefully).</p>',
    "16": '<p><strong>ʾădōnāy ʿălêhem yiḥyû</strong> — "O Lord, by these things men live, and in all these is the life of my spirit." The "things" refer to the divine words, promises, and judgments that filled the psalm. Human life is sustained not merely by physical health but by the content of YHWH\'s address to his people. <strong>wĕtaḥălîmēnî wĕhaḥăyēnî</strong> — "restore me to health and give me life" — the prayer for healing is embedded within the broader theological vision of life as YHWH\'s gift.</p>',
    "17": '<p><strong>hinnēh lĕšālôm mar-lî mar</strong> — "behold, it was for my welfare that I had great bitterness" — the retrospective theology of suffering. The bitterness proved to be the instrument of peace (<em>šālôm</em>). <strong>wĕʾattâ ḥāšaqtā napšî miššaḥat bĕlî</strong> — "but you have loved/desired (<em>ḥāšaq</em>, H2836, to delight in, to be attached to) my soul from the pit of destruction." <strong>kî hišlaḵtā ʾaḥărê gēwĕkā kol-ḥăṭāʾāy</strong> — "you have cast all my sins behind your back" — the forgiveness of sins coupled with the healing of the body.</p>',
    "18": '<p><strong>kî lōʾ šĕʾôl tôdekkā māwet yĕhallĕlekkā</strong> — "for Sheol does not thank you, death does not praise you" — the theological argument for healing from the perspective of worship. Those who go down to the pit (<em>yôrĕdê bôr</em>) do not hope for YHWH\'s faithfulness (<em>ʾel-ʾămittekā</em>). Hezekiah\'s argument is not that he deserves to live but that the dead cannot praise YHWH — and YHWH desires the praise of his creatures. This praise-theology argument for healing is unique in the Hebrew Bible.</p>',
    "19": '<p><strong>ḥāy ḥāy hûʾ yôdekā kāmônî hayyôm</strong> — "the living, the living, they praise you, as I do today" — the doubled <em>ḥāy</em> (living, living) mirrors the doubled <em>Yāh Yāh</em> of v.11 — two anguished calls to YHWH now become two declarations of living praise. <strong>ʾāḇ lĕḇānîm yôdîaʿ ʾel-ʾămittekā</strong> — "a father makes known to his children your faithfulness" — intergenerational transmission of praise is only possible through continued life. Hezekiah\'s argument climaxes here.</p>',
    "20": '<p><strong>Yhwh lĕhôšîʿēnî</strong> — "YHWH will save me" — the concluding confidence statement. <strong>ûnĕgînôtay nĕnaggen kol-yĕmê ḥayyênû ʿal-bêt Yhwh</strong> — "we will play my songs on stringed instruments all the days of our life at the house of YHWH." The plural <em>nĕnaggen</em> (we will play) and <em>ḥayyênû</em> (our life) suggest communal temple worship — Hezekiah\'s individual healing becomes the occasion for shared liturgical music. The temple is the site of realized salvation.</p>',
    "21": '<p><strong>wayyōʾmer Yĕšaʿyāhû</strong> — "Isaiah said" — a surprising appendix after the psalm. <strong>yiśśĕʾû dĕbelet tĕʾēnîm</strong> — "let them take a cake of figs" (<em>debelet</em>, H1690, a fig-cake, a pressed lump of dried figs). The medical instruction — applying a poultice of figs to the boil (<em>šĕḥîn</em>) — reflects ancient Near Eastern medical practice where figs were used therapeutically. The miraculous healing and the natural medical treatment coexist without tension in the narrative.</p>',
    "22": '<p><strong>wayyōʾmer Ḥizqiyyāhû mah ʾôt kî ʾeʿĕleh bêt Yhwh</strong> — "Hezekiah had said, \'What is the sign that I shall go up to the house of YHWH?\'" — this retrospective verse appears to have been displaced from its logical position (after v.7, where the sign is given). Its placement here may be an editorial note showing that Hezekiah\'s recovery was validated by his ability to return to the temple — the ultimate mark of restored communion with YHWH.</p>',
  },
  "39": {
    "1": '<p><strong>bĕrōdak balʾăḏān ben-balʾăḏān melek bābel</strong> — Merodach-Baladan (Marduk-apla-iddina II), the Chaldean king of Babylon who twice ruled Babylon (722-710 BCE and briefly 703 BCE) and consistently opposed Assyrian power. His envoys with a letter and a gift (<em>sĕpārîm ûminḥâ</em>) come to Hezekiah because he has heard of his illness. The diplomatic context: Babylon was seeking anti-Assyrian alliances. Hezekiah\'s reception of these envoys becomes the seed of the Babylonian exile prophesied in vv.5-7.</p>',
    "2": '<p><strong>wayyiśmaḥ ʿălêhem Ḥizqiyyāhû</strong> — "Hezekiah was pleased/glad with them" — the dangerous delight. <strong>wayyarʾēm ʾet-bêt nĕkōtôh</strong> — "showed them his house of treasures" (<em>nĕkōt</em>, H5238, spice/treasure; <em>bêt nĕkōt</em>, the treasury). <strong>ʾet-hakkesef wĕʾet-hazzāhāb</strong> — silver, gold, spices, fine oil, the entire armory, and everything in the storehouses — Hezekiah shows everything. The comprehensiveness is repeated: <strong>lōʾ-hāyâ dābār ʾăšer lōʾ-herʾām</strong> — "there was nothing that he did not show them."</p>',
    "3": '<p>Isaiah\'s opening question: <strong>mā ʾāmĕrû hāʾănāšîm hāʾēlleh ûmēʾayin yāḇōʾû ʾēleykā</strong> — "what did these men say, and where did they come from?" Hezekiah answers proudly: <strong>mēʾereṣ rĕḥôqâ bāʾû ʾēlay mibābel</strong> — "from a distant land they came to me, from Babylon." The word <em>rĕḥôqâ</em> (distant) is the geographical marker that anticipates the later exile — what came from afar will take everything there.</p>',
    "4": '<p><strong>mah rāʾû bĕbêtekā</strong> — "what did they see in your house?" — Isaiah presses. Hezekiah answers with complete candor: <strong>kōl ʾăšer bĕbêtî rāʾû</strong> — "everything in my house they saw." <strong>lōʾ-hāyâ dābār ʾăšer lōʾ-herʾîtîm bĕʾôṣĕrōtāy</strong> — "there was nothing in my treasuries that I did not show them." The repetition of "nothing not shown" from v.2 and v.4 frames the indictment — Hezekiah has confirmed his own guilt.</p>',
    "5": '<p><strong>šĕmaʿ dĕbar Yhwh ṣĕbāʾôt</strong> — "hear the word of YHWH of hosts" — the prophetic formula that introduces a hard word. The shift from conversation to oracle marks a change in register. Isaiah\'s words become the voice of YHWH, not his own assessment. The oracle will address the consequences of Hezekiah\'s hospitality to Babylon\'s representative.</p>',
    "6": '<p><strong>hinnēh yāmîm bāʾîm</strong> — "behold, days are coming" — the prophetic future formula. <strong>wĕnuśśāʾ kol-ʾăšer bĕbêtekā</strong> — "everything in your house will be carried off (<em>nāśāʾ</em>)" — the same verb as the Babylonian exile deportations. <strong>wĕʾăšer ʾāṣĕrû ʾăḇōteykā ʿad-hayyôm hazzeh bābel yūbāʾû</strong> — "what your fathers stored up until this day will be brought to Babylon." The treasure that Hezekiah showed becomes the treasure that will be removed — the showing was already the beginning of the losing.</p>',
    "7": '<p><strong>ûmibānêkā ʾăšer yēṣĕʾû mimměkā</strong> — "and of your sons who will come from you" — Hezekiah\'s descendants will be taken. <strong>wĕhāyû sārîsîm bĕhêkal melek bābel</strong> — "they will be eunuchs in the palace of the king of Babylon" (<em>sārîs</em>, H5631, eunuch/court official). This specific prophecy is regarded as fulfilled in the Babylonian exile — Israelite youths of the royal line serving in Babylonian courts (cf. Dan 1:1-7 where Daniel and his companions are exactly this). The use of <em>sārîs</em> may refer to court officials generally or specifically to castration.</p>',
    "8": '<p><strong>wayyōʾmer Ḥizqiyyāhû ʾel-Yĕšaʿyāhû ṭôḇ dĕbar-Yhwh ʾăšer dibbartā</strong> — "Hezekiah said to Isaiah, \'The word of YHWH that you have spoken is good.\'" The response is theologically proper — accepting the divine word — but the following clause reveals its limitation: <strong>kî yihyeh šālôm weʾĕmet bĕyāmay</strong> — "for there will be peace and truth in my days." Hezekiah is content because the disaster will not come in his lifetime. The commentary tradition has long noted the moral ambiguity: is this faith (accepting YHWH\'s sovereignty) or selfishness (relief that others will bear it)?</p>',
  },
  "40": {
    "1": '<p><strong>naḥămû naḥămû ʿammî</strong> — "Comfort, comfort my people" — the opening imperative of the great prologue, doubled for emphasis (infinitive absolute construction: absolute certainty). The structural break from chs 1-39 is marked by content, not form — no superscription, but a complete change of tone from judgment to consolation. <strong>yōʾmar ʾĕlōhêkem</strong> — "says your God" — the comfort is commanded by God and addressed to God\'s own people in the possessive (<em>ʿammî</em>, "my people").</p>',
    "2": '<p><strong>dibbĕrû ʿal-lēb yĕrûšālaim</strong> — "speak to the heart of Jerusalem" — the intimate address formula (<em>dibbēr ʿal-lēb</em>, to speak to the heart, used in courtship: Gen 34:3; Ruth 2:13; Hos 2:14). The comfort has the character of a lover\'s tender speech, not a legal announcement. <strong>ṣĕbāʾāh mālĕʾâ</strong> — "her hard service is completed" (<em>ṣāḇāʾ</em>, H6635, army/forced service); <strong>nirsâ ʿăwōnāh</strong> — "her iniquity is pardoned/accepted." <strong>kî lāqĕḥâ miyyad Yhwh kiflayim</strong> — "she has received from YHWH\'s hand double for all her sins" — the double payment formula implies both the debt is fully settled and the grace exceeds the requirement.</p>',
    "4": '<p><strong>kol-gay yinnāśēʾ wĕkol-har wĕgibʿâ yišpālû</strong> — "every valley will be lifted up, and every mountain and hill made low" — the cosmogonic leveling of creation to prepare the divine highway (<em>derekh</em>). The reversal of terrain — valley elevated, mountain lowered — describes not physical geography but the removal of all obstacles to YHWH\'s coming. <strong>wĕhāyâ heʿāqōb lĕmîšôr</strong> — "the rough ground will become level" (<em>mîšôr</em>, H4334, a level plain).</p>',
    "5": '<p><strong>wĕniglâ kĕbôd Yhwh</strong> — "the glory of YHWH will be revealed" (<em>gālâ</em>, niphal — disclosed, unveiled). <strong>wĕrāʾû kol-bāśār yaḥdāw</strong> — "and all flesh will see it together" — the revelation of divine glory to all humanity simultaneously and without exception (<em>kol-bāśār</em>, all flesh). <strong>kî pî Yhwh dibber</strong> — "for the mouth of YHWH has spoken" — the guarantee is the divine speech-act itself, which cannot be undone.</p>',
    "6": '<p><strong>qôl ʾōmēr qĕrāʾ wĕʾāmar mā ʾeqrāʾ</strong> — "a voice says \'Call out!\' and one asks \'What shall I call out?\'" — the dialogue introducing the grass/flower oracle. <strong>kol-habbāśār ḥāṣîr wĕkol-ḥasdô kĕṣîṣ haśśādeh</strong> — "all flesh is grass, and all its steadfast love/glory is like the flower of the field." The word <em>ḥeseḏ</em> here is unusual in this context — it is usually YHWH\'s characteristic; applied to human beings it may be ironic: what humans regard as their greatest virtue is as ephemeral as a wildflower. 1 Pet 1:24-25 quotes vv.6-8.</p>',
    "7": '<p><strong>yābēš ḥāṣîr nābēl ṣîṣ kî rûaḥ Yhwh nāšĕpâ bô</strong> — "the grass withers, the flower fades when the breath/Spirit of YHWH blows on it" — YHWH\'s <em>rûaḥ</em> both gives life (Gen 2:7) and withdraws it. The <em>rûaḥ</em> here is the scorching desert wind, but also implicitly the divine breath that makes life contingent. <strong>ʾākēn ḥāṣîr hāʿām</strong> — "surely the people are grass" — the application to humanity is explicit. All human civilization is as impermanent as vegetation.</p>',
    "8": '<p><strong>yābēš ḥāṣîr nābēl ṣîṣ</strong> — "the grass withers, the flower fades" — repeated from v.7 for emphasis and then completed with the contrast: <strong>ûdĕbar ʾĕlōhênû yāqûm lĕʿôlām</strong> — "but the word of our God stands forever." The contrast is absolute: created matter is ephemeral; divine word is permanent. 1 Pet 1:25 applies this to the gospel: "this word is the good news that was preached to you." The eternal word takes the form of the preached gospel.</p>',
    "9": '<p><strong>mĕbaśśeret ṣiyyôn</strong> — "herald of good news to Zion" — the root <em>bāśar</em> (H1319) is the verb underlying <em>bĕśôrâ</em> (good news) and the Greek <em>evangelion</em>. The herald who brings good news of YHWH\'s coming is the precursor to the NT concept of gospel proclamation. <strong>rômî bakkōaḥ qôleḵ</strong> — "lift up your voice with strength" — the herald is commanded to amplify, not whisper. <strong>ʾimrî lĕʿārê yĕhûdâ hinnēh ʾĕlōhêkem</strong> — "say to the cities of Judah, \'Behold, your God!\'" — the content of the gospel is the announcement of God\'s arrival.</p>',
    "10": '<p><strong>hinnēh ʾădōnāy Yhwh bĕḥāzāq yābōʾ</strong> — "behold, Lord YHWH comes with might/power" — the coming is not quiet but powerful (<em>bĕḥāzāq</em>, with strength). <strong>ûzrōʿô mōšlâ lô</strong> — "his arm rules for him" — the strong arm of YHWH is the instrument of sovereign rule. <strong>hinnēh śĕkārô ʾittô ûpĕullātô lĕpānāyw</strong> — "his reward (<em>śākār</em>) is with him, and his recompense (<em>pĕullâ</em>) before him" — the formula repeated in 62:11 and Rev 22:12 where Christ comes with his recompense.</p>',
    "11": '<p><strong>kĕrōʿeh ʿēḏrô yirʿeh bizrōʿô yĕqabbēṣ ṭĕlāʾîm</strong> — "like a shepherd he pastures his flock; with his arm he gathers the lambs." The contrast with v.10\'s powerful arm: the same arm that rules (v.10) is the arm that gathers (<em>qābaṣ</em>) the lambs. <strong>ûbĕḥêqô yiśśāʾ</strong> — "and carries them in his bosom/breast" — the image of divine tenderness in the context of sovereign power. The shepherd imagery here is taken up in John 10:11 and Luke 15:4-7. <strong>ʿālôt yĕnahēl</strong> — "he gently leads the nursing ewes."</p>',
    "12": '<p><strong>mî-māddad bĕšāʿlô mayim</strong> — "who has measured the waters in the hollow of his hand?" (<em>šaʿal</em>, the cupped palm — measuring water in the hollow of one\'s hand). <strong>wĕkāl baśśālîš ʿāpār hāʾāreṣ</strong> — "and marked off the heavens with a span" (<em>šālîš</em>, H8027, a third — the unit of the hand-span), <strong>wĕkāl baśśālîš ʿāpār hāʾāreṣ</strong> — "and enclosed the dust of the earth in a measure." The creation-scale measurements are expressed in human body-measure terms — the cosmic is rendered comprehensible through embodied metaphor.</p>',
    "13": '<p><strong>mî-tikkēn ʾet-rûaḥ Yhwh</strong> — "who has measured/directed the Spirit of YHWH?" (<em>tākan</em>, H8505, to regulate, measure, direct). <strong>wĕʾîš ʿăṣātô yôdîʿennû</strong> — "and what counselor (<em>ʾîš ʿăṣâ</em>) made him know?" Paul quotes this in Rom 11:34 ("Who has known the mind of the Lord, or who has been his counselor?") and 1 Cor 2:16 ("who has known the mind of the Lord so as to instruct him?"). The independence of divine wisdom from human instruction is absolute — YHWH was not taught by anyone.</p>',
    "14": '<p><strong>ʾet-mî nôʿāṣ wayyĕbînēhû</strong> — "with whom did he take counsel, and who made him understand?" — the series of rhetorical questions continues. <strong>wayyĕlammdēhû bĕʾōraḥ mišpāṭ</strong> — "who taught him the path of justice?" None. The point is YHWH\'s absolute independence of mind — he was not mentored in wisdom, justice, or knowledge by any created being. His wisdom is not derived but original.</p>',
    "15": '<p><strong>hēn gôyim kĕmar middĕlî</strong> — "behold, the nations are like a drop from a bucket" (<em>mar</em>, a drip/drop; <em>dĕlî</em>, a bucket/vessel for drawing water). <strong>ûkĕšaḥaq mōzĕnayim neḥšĕḇû</strong> — "reckoned as dust on the scales" (<em>šaḥaq</em>, fine dust, the kind too light to register on a balance). The political powers that overwhelm human experience are, from YHWH\'s perspective, negligible. The cosmic creator views the greatest empires as irrelevant weight.</p>',
    "16": '<p><strong>ûlĕḇānôn ʾên dî bāʿēr</strong> — "Lebanon is not sufficient for fuel" — even the endless cedars of Lebanon would not produce enough wood for a sacrifice worthy of YHWH. <strong>wĕḥayyātô ʾên dî ʿôlâ</strong> — "and its animals are not sufficient for a burnt offering." The point is not that sacrifice is useless but that no created abundance is adequate to honor the Creator — the gap between creature and Creator is infinite.</p>',
    "17": '<p><strong>kol-haggôyim kĕʾayim negdô</strong> — "all the nations are as nothing before him" — <em>ʾayim</em> (H657, H408) — nothingness, non-existence. <strong>mēʾepes wātōhû neḥšĕḇû-lô</strong> — "they are accounted as less than nothing (<em>ʾepes</em>, zero/end) and emptiness (<em>tōhû</em>, the same as Gen 1:2\'s primeval chaos) to him." The nations are not merely small — they are below the threshold of being. YHWH\'s perspective reduces all geopolitical significance to zero.</p>',
    "18": '<p><strong>wĕʾel-mî tĕdammĕyûn ʾēl</strong> — "to whom then will you liken God (<em>ʾēl</em>)?" — the decisive anti-idol question. <strong>ûmah-dĕmût taʿărĕkû lô</strong> — "what likeness will you set up to compare with him?" The question opens the idol polemic that Isaiah 40-48 develops at length (cf. 44:9-20; 46:1-13). Any human representation of YHWH is by definition inadequate — not merely aesthetically limited but ontologically impossible.</p>',
    "19": '<p>The idol\'s manufacture: <strong>happesel nāsak ḥārāš</strong> — "the craftsman casts an idol" (<em>pesel</em>, carved/cast image; <em>nāsak</em>, to pour/cast molten metal). <strong>wĕṣōrēp bazzāhāb yĕraqqĕʿennû</strong> — "the goldsmith overlays it with gold" (<em>rāqaʿ</em>, to hammer thin, to plate). <strong>ûrĕtuqôt kesep ṣōrēp</strong> — "the silversmith casts chains of silver" — the finishing work of the idol production. The detailed manufacturing description makes the point: this thing was made by human hands, step by step. It is entirely a human product.</p>',
    "20": '<p><strong>hamesukkān tĕrûmâ</strong> — "the one who is too poor for a dedicatory offering" (<em>sukkān</em>, H5539, impoverished — debated) selects wood that will not rot (<em>ʿēṣ lōʾ-yirqāb</em>). He seeks a skilled craftsman (<em>ḥākām</em>) to set up an idol that will not move (<em>lōʾ-yimmôṭ</em>). The irony is the goal: the idol\'s primary virtue is that it stays put — it does not move. YHWH\'s defining characteristic is that he acts, speaks, and intervenes. The static stability of the idol is the exact opposite of the dynamic activity of YHWH.</p>',
    "21": '<p><strong>hălōʾ tēdĕʿû hălōʾ tišmāʿû</strong> — "do you not know? Do you not hear?" — four rhetorical questions challenging the idol-makers\' ignorance. <strong>hălōʾ huggad lākem mērōʾš</strong> — "was it not told you from the beginning?" <strong>hălōʾ hĕḇînottem môsĕdôt hāʾāreṣ</strong> — "have you not understood from the foundations of the earth?" The knowledge of YHWH\'s creative sovereignty is not new revelation but primordial truth available to all — the idol-maker\'s error is culpable ignorance, not innocent confusion.</p>',
    "22": '<p><strong>hayyōšēḇ ʿal-ḥûg hāʾāreṣ</strong> — "he who sits above the circle of the earth" (<em>ḥûg</em>, H2329, circle/vault/arc). <strong>wĕyōšĕḇêhā kĕḥăgāḇîm</strong> — "and its inhabitants are like grasshoppers" — the divine perspective on humanity. From YHWH\'s cosmic vantage point, the great nations and their inhabitants are as small and numerous as grasshoppers in a field. <strong>hannōṭeh kaḏōq šāmayim</strong> — "who stretches out the heavens like a curtain" (<em>dōq</em>, H1852, thin cloth/gauze).</p>',
    "23": '<p><strong>hannōtēn rôzĕnîm lāʾayin</strong> — "who brings princes to nothing" — <em>rôzĕnîm</em> (H7336, rulers/princes, from <em>rāzan</em>, to be weighty/authoritative). <strong>šōpĕṭê ʾāreṣ kattōhû ʿāśâ</strong> — "makes the judges of the earth as nothing (<em>tōhû</em>)." The application of the creation vocabulary of Gen 1:2 (<em>tōhû</em>) to human rulers is pointed: the great political powers are returned to primeval formlessness by YHWH\'s action.</p>',
    "24": '<p><strong>ʾap bal-niṭṭāʿû ʾap bal-zōrāʿû ʾap bal-šōrēš bāʾāreṣ gizʿām</strong> — "scarcely planted, scarcely sown, scarcely has their stem taken root in the earth" — the three <em>ʾap bal</em> ("hardly... not yet") constructions describe the briefness of a ruler\'s establishment. <strong>wayyiggaʿ bāhem wayyi bāšû</strong> — "he blows on them and they wither" — YHWH\'s breath (<em>nāšap</em>, blow) is all it takes to end a reign. <strong>ûsĕʿārâ kaqaš tiśśāʾēm</strong> — "and a whirlwind carries them off like stubble."</p>',
    "25": '<p><strong>wĕʾel-mî tĕdammĕyûnî wĕʾeśweh</strong> — "to whom then will you compare me, that I should be like him?" — YHWH himself asks the anti-idol question (the same as v.18 but now in the first person). <strong>yōʾmar qādôš</strong> — "says the Holy One." The divine self-designation <em>qādôš</em> (Holy One — Isaiah\'s signature divine title: 1:4; 5:19,24; 6:3; 10:17; 12:6; 17:7; etc.) reasserts incomparability from YHWH\'s own mouth.</p>',
    "26": '<p><strong>śĕʾû mārôm ʿênêkem ûrĕʾû mî-bārāʾ ʾēlleh</strong> — "lift up your eyes on high and see: who created these?" — the command to look at the stars as evidence for the Creator. <strong>hammôṣiʾ bĕmispār ṣĕbāʾām</strong> — "who brings out their host by number" (<em>ṣĕbāʾ</em>, army/host — the stars as YHWH\'s cosmic army mustered and reviewed). <strong>lĕkullām bĕšēm yiqrāʾ</strong> — "to all of them he calls by name" — the naming of each star by YHWH is both the assertion of sovereignty and of intimate knowledge. <strong>mērōb ʾônîm wĕʾammîṣ kōaḥ ʾîš lōʾ neʿĕdār</strong> — "because of his great might, and the strength of his power, not one is missing."</p>',
    "27": '<p><strong>lāmmâ tōʾmar yaʿăqōb ûtĕdabbēr yiśrāʾēl nistarrâ darkî mēyhwh</strong> — "why do you say, O Jacob, and speak, O Israel, \'My way is hidden from YHWH, and my right/justice is passed over by my God\'?" — the despairing complaint of exile: YHWH does not see our suffering; our case goes unheard. The questions are not accusations but pastoral address — YHWH engages the people\'s doubt, not dismissing it but answering it.</p>',
    "28": '<p><strong>hălōʾ yāḏaʿtā ʾim-lōʾ šāmaʿtā</strong> — "Have you not known? Have you not heard?" — the same rhetorical questions as v.21, now applied to the Israelites themselves. <strong>ʾĕlōhê ʿôlām Yhwh bōrēʾ qĕṣôt hāʾāreṣ</strong> — "YHWH is the everlasting God (<em>ʾĕlōhê ʿôlām</em>), the Creator of the ends of the earth." <strong>lōʾ yîʿap wĕlōʾ yîgāʿ</strong> — "he does not faint or grow weary" — the same verbs used of the exhausted exiles in vv.29-31 are denied of YHWH. His inexhaustible energy is the source of renewed energy for the weary.</p>',
    "29": '<p><strong>nōtēn lĕyāʿēp kōaḥ</strong> — "he gives power to the faint/exhausted" (<em>yāʿēp</em>, H3287, exhausted). <strong>ûlĕʾên ʾônîm ʿaṣmâ yarbeh</strong> — "and to him who has no might he increases strength" (<em>ʾôn</em>, H202, strength, vigor — "no strength" is the absolute exhaustion of exile). The divine pattern: YHWH gives to those who have nothing, increases to those who lack. This is not a reward for the strong but a gift to the weak — the theology of grace in concentrated form.</p>',
    "30": '<p><strong>yîʿăpû nĕʿārîm wĕyîgāʿû</strong> — "even youths (<em>nāʿar</em>) will faint and grow weary" — the young, who should have the most energy, are not exempt from exhaustion. <strong>ûbaḥûrîm kāšôl yikkāšēlû</strong> — "and young men (<em>bāḥûr</em>, choice/selected young men, the military elite) will fall exhausted." Human strength at its peak cannot sustain itself indefinitely. The point is not pessimism but preparation for the contrast in v.31.</p>',
    "31": '<p><strong>wĕqôwê Yhwh yaḥălîpû kōaḥ</strong> — "but those who wait on/hope in YHWH will renew/exchange strength" (<em>qāwâ</em>, H6960, to wait, to hope with expectant tension — cf. 25:9; 26:8; 33:2; 49:23). The verb <em>ḥālaP</em> (H2498, to exchange, to renew, to sprout fresh) suggests not merely restoration but transformation — new strength replacing old. <strong>yaʿălû ʾēḇer kannĕšārîm</strong> — "they will soar on wings like eagles" (<em>nešer</em>, the large bird of prey — eagle or vulture). <strong>yārûṣû wĕlōʾ yîgāʿû yēlĕkû wĕlōʾ yîʿāpû</strong> — "they will run and not grow weary, they will walk and not faint" — the progression moves from soaring (extraordinary) to running (normal effort) to walking (ordinary pace), all sustained by YHWH\'s energy.</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-original', 'isaiah', existing)
    # INTENT: Verify all Isaiah 37-40 mkt-original verses present; ch 40:3 was pre-existing
    # CHANGE? If interlinear/isaiah.json verse counts change, update expected range check
    # VERIFY: Console shows OK for all 4 chapters; no MISSING verses reported
    il = json.loads((ROOT / 'data' / 'interlinear' / 'isaiah.json').read_text())
    out = json.loads((ROOT / 'data' / 'commentary' / 'mkt-original' / 'isaiah.json').read_text())
    missing = []
    for ch in range(37, 41):
        ck = str(ch)
        for v in il.get(ck, {}):
            if v not in out.get(ck, {}):
                missing.append(f'{ch}:{v}')
    if missing:
        print(f'  MISSING: {missing}')
    else:
        total = sum(len(il.get(str(c), {})) for c in range(37, 41))
        print(f'  OK: all Isaiah 37-40 mkt-original verses present ({total} verses)')

if __name__ == '__main__':
    main()
